class Solution:
    def minimumString(self, a: str, b: str, c: str) -> str:
        def merge(s1: str, s2: str) -> str:
            # Returns the shortest string that contains both s1 and s2 as substrings
            if s1 in s2:
                return s2
            if s2 in s1:
                return s1
            # Try all possible combinations of s1 and s2
            candidates = [s1 + s2, s2 + s1]
            # Find the shortest one, and if equal, the lexicographically smallest
            return min(candidates, key=lambda x: (len(x), x))

        # Generate all permutations of the three strings
        from itertools import permutations
        candidates = set()
        for perm in permutations([a, b, c]):
            merged = merge(merge(perm[0], perm[1]), perm[2])
            candidates.add(merged)

        # Find the minimum length string, and among those, the lexicographically smallest
        return min(candidates, key=lambda x: (len(x), x))
